import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { membersAPI, tripsAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';

export default function Members() {
  const { tripId } = useParams();
  const { user: currentUser } = useAuth();
  const [trip, setTrip] = useState(null);
  const [members, setMembers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const toast = useToast();

  // Add Member form state
  const [emailInput, setEmailInput] = useState('');
  const [adding, setAdding] = useState(false);
  const [addMessage, setAddMessage] = useState({ type: '', text: '' });

  const fetchData = async () => {
    try {
      const [tripData, membersData] = await Promise.all([
  tripsAPI.getOne(tripId),   
  membersAPI.getAll(tripId),
]);
      setTrip(tripData);
      setMembers(membersData);
    } catch (err) {
      console.error(err);
      setError('Failed to fetch crew details.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [tripId]);

  const handleAddMemberSubmit = async (e) => {
    e.preventDefault();
    setAddMessage({ type: '', text: '' });

    if (!emailInput.trim()) return;

    setAdding(true);
    try {
      const newMember = await membersAPI.add(tripId, emailInput);
      setMembers((prev) => [...prev, newMember]);
      setEmailInput('');
      toast.success('Member added to your travel crew! 🎉');
    } catch (err) {
      console.error(err);
      const msg = err.response?.data?.message || 'Failed to add member.';
      const toastMsg = msg.includes('not found')
        ? 'This email is not registered with TripNest. Ask your friend to register first!'
        : msg;
      setAddMessage({
        type: 'error',
        text: toastMsg,
      });
      toast.error(toastMsg);
    } finally {
      setAdding(false);
    }
  };

const handleRemoveMember = async (userId) => {
  const confirmed = await toast.confirm('Remove this member from the trip?', 'Remove');
  if (!confirmed) return;

  try {
    await membersAPI.remove(tripId, userId);
    setMembers((prev) => prev.filter((m) => m.user?._id !== userId));
    toast.success('Member removed from crew.');
  } catch (err) {
    console.error(err);
    toast.error('Failed to remove member.');
  }
};

const handleMakeOwner = async (userId, userName) => {
  const confirmed = await toast.confirm(
    `Make ${userName} an owner of this trip?`,
    'Make Owner 👑'
  );
  if (!confirmed) return;

  try {
    await tripsAPI.update(tripId, { owner: userId });
    toast.success(`${userName} is now the trip owner! 👑`);
    fetchData();
  } catch (err) {
    console.error(err);
    toast.error('Failed to transfer ownership.');
  }
};

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[80vh]">
        <div className="w-10 h-10 border-4 border-primary-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  if (error || !trip) {
    return (
      <div className="p-8 text-center max-w-md mx-auto min-h-[50vh] flex flex-col justify-center items-center">
        <p className="text-4xl mb-3">⚠️</p>
        <h2 className="font-display font-bold text-xl text-gray-800 mb-2">Error</h2>
        <p className="text-sm text-gray-500 mb-6">{error || 'Could not load crew list.'}</p>
        <Link to="/trips" className="px-5 py-2.5 bg-primary-600 text-white rounded-xl text-sm font-semibold hover:bg-primary-700 transition-colors">
          Back to My Trips
        </Link>
      </div>
    );
  }
const ownerId = trip.owner?._id || trip.owner;
const isOwner = ownerId?.toString() === currentUser.id?.toString();

  return (
    <div className="p-8 max-w-7xl mx-auto">
      {/* Header */}
        <Link to={`/trips/${tripId}`} className="text-sm text-gray-400 hover:text-primary-600 transition-colors mb-4 inline-flex items-center gap-1">
        ← {trip?.name || 'Trip'}
      </Link>
      <div className="mb-8">
        <span className="text-xs font-bold text-primary-600 uppercase tracking-widest">Crew Manager</span>
        <h1 className="font-display font-bold text-3xl text-gray-900 mt-1">
          {trip.emoji} {trip.name} Crew
        </h1>
        <p className="text-gray-500 text-sm mt-1">📍 {trip.destination} · Manage travel partners and splitting privileges.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Crew list */}
        <div className="lg:col-span-2 bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
          <div className="p-5 border-b border-gray-100">
            <h2 className="font-display font-bold text-lg text-gray-800">Travel Crew ({members.length})</h2>
          </div>
          <div className="divide-y divide-gray-50">
            {members.map((member) => {
              const u = member.user || {};
             const isPayerOwner = ownerId?.toString() === u._id?.toString();
              return (
                <div
  key={t.id}
  className={`toast-enter flex flex-col p-4 rounded-2xl shadow-xl backdrop-blur-md border border-gray-100 w-full pointer-events-auto ${typeMeta.bg}`}
  style={{ transition: 'all 0.25s ease-in-out' }}
>
  <div className="flex items-center justify-between">
    <div className="flex items-center gap-3">
      <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-sm font-semibold flex-shrink-0 ${typeMeta.iconBg}`}>
        {typeMeta.icon}
      </div>
      <p className="text-xs font-semibold">{t.message}</p>
    </div>
    {t.type !== 'confirm' && (
      <button
        onClick={() => removeToast(t.id)}
        className="text-gray-400 hover:text-gray-600 text-sm font-bold pl-3 flex-shrink-0"
      >
        ✕
      </button>
    )}
  </div>

  {t.type === 'confirm' && (
    <div className="flex gap-2 mt-3 pl-11">
      <button
        onClick={t.onCancel}
        className="flex-1 py-1.5 text-xs font-medium border border-gray-200 text-gray-600 rounded-lg hover:bg-gray-50 transition-colors"
      >
        Cancel
      </button>
      <button
        onClick={t.onConfirm}
        className="flex-1 py-1.5 text-xs font-medium bg-amber-500 text-white rounded-lg hover:bg-amber-600 transition-colors"
      >
        {t.confirmLabel || 'Confirm'}
      </button>
    </div>
  )}
</div>
              )
            })}
          </div>
        </div>

        {/* Invite Form */}
        <div className="bg-white rounded-3xl border border-gray-100 shadow-sm p-6 self-start space-y-4">
          <h3 className="font-display font-bold text-lg text-gray-800">Add Crew Member</h3>
          <p className="text-xs text-gray-400 leading-relaxed">
            Invite friends to join this trip. Once added, they will be able to view details, plan itineraries, and log expenses.
          </p>

          {isOwner ? (
            <form onSubmit={handleAddMemberSubmit} className="space-y-3">
              <div>
                <input
                  type="email"
                  placeholder="friend@email.com"
                  value={emailInput}
                  onChange={(e) => setEmailInput(e.target.value)}
                  className="w-full px-4 py-2.5 border border-gray-200 rounded-xl text-sm"
                  required
                />
              </div>

              {addMessage.text && (
                <p className={`text-xs ${addMessage.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>
                  {addMessage.type === 'success' ? '✅' : '⚠️'} {addMessage.text}
                </p>
              )}

              <button
                type="submit"
                disabled={adding}
                className="w-full py-2.5 bg-gradient-to-r from-primary-600 to-emerald-500 text-white font-semibold text-sm rounded-xl
                  hover:from-primary-700 hover:to-emerald-600 shadow-md transition-all flex items-center justify-center gap-1.5"
              >
                {adding ? 'Inviting...' : 'Invite Friend'}
              </button>
            </form>
          ) : (
            <div className="p-3.5 bg-gray-50 border border-gray-150 rounded-xl text-xs text-gray-500 leading-relaxed">
              🔒 Only the trip owner (<strong>{members.find((m) => m.user?._id === trip.owner)?.user?.name || 'Creator'}</strong>) can add or remove crew members.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
